void nnc_maxpool2d(
    Tensor* input, Tensor* output,
    int kernel_h, int kernel_w,
    int stride_h, int stride_w,
    int pad_h, int pad_w
) {
    /* 2D Max Pooling implementation
     * Input: [N, C, H, W]
     * Output: [N, C, H_out, W_out]
     * H_out = (H + 2*pad_h - kernel_h) / stride_h + 1
     * W_out = (W + 2*pad_w - kernel_w) / stride_w + 1
     */

    if (!input || !output || !input->data || !output->data) {
        return;
    }
    if (input->ndim != 4 || output->ndim != 4) {
        return;
    }

    int N = (int)input->shape[0];
    int C = (int)input->shape[1];
    int H_in = (int)input->shape[2];
    int W_in = (int)input->shape[3];
    int H_out = (int)output->shape[2];
    int W_out = (int)output->shape[3];

    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    /* Initialize output to minimum float value */
    for (int64_t i = 0; i < tensor_numel(output); i++) {
        out_data[i] = -3.402823e38f;  /* FLT_MIN-ish but for max pool */
    }

    /* Compute max pooling */
    for (int n = 0; n < N; n++) {
        for (int c = 0; c < C; c++) {
            for (int h_out = 0; h_out < H_out; h_out++) {
                for (int w_out = 0; w_out < W_out; w_out++) {
                    /* Calculate input window start position */
                    int h_start = h_out * stride_h - pad_h;
                    int w_start = w_out * stride_w - pad_w;

                    /* Calculate window end position */
                    int h_end = h_start + kernel_h;
                    int w_end = w_start + kernel_w;

                    /* Clamp to input bounds */
                    if (h_start < 0) h_start = 0;
                    if (w_start < 0) w_start = 0;
                    if (h_end > H_in) h_end = H_in;
                    if (w_end > W_in) w_end = W_in;

                    /* Find maximum in window */
                    float max_val = -3.402823e38f;
                    int has_valid = 0;

                    for (int h = h_start; h < h_end; h++) {
                        for (int w = w_start; w < w_end; w++) {
                            int64_t in_idx = ((n * C + c) * H_in + h) * W_in + w;
                            float val = in_data[in_idx];
                            if (!has_valid || val > max_val) {
                                max_val = val;
                                has_valid = 1;
                            }
                        }
                    }

                    /* Write output */
                    int64_t out_idx = ((n * C + c) * H_out + h_out) * W_out + w_out;
                    out_data[out_idx] = max_val;
                }
            }
        }
    }
}

void nnc_avgpool2d(
    Tensor* input, Tensor* output,
    int kernel_h, int kernel_w,
    int stride_h, int stride_w,
    int pad_h, int pad_w
) {
    /* 2D Average Pooling implementation
     * Input: [N, C, H, W]
     * Output: [N, C, H_out, W_out]
     * H_out = (H + 2*pad_h - kernel_h) / stride_h + 1
     * W_out = (W + 2*pad_w - kernel_w) / stride_w + 1
     */

    if (!input || !output || !input->data || !output->data) {
        return;
    }
    if (input->ndim != 4 || output->ndim != 4) {
        return;
    }

    int N = (int)input->shape[0];
    int C = (int)input->shape[1];
    int H_in = (int)input->shape[2];
    int W_in = (int)input->shape[3];
    int H_out = (int)output->shape[2];
    int W_out = (int)output->shape[3];

    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    /* Compute average pooling */
    for (int n = 0; n < N; n++) {
        for (int c = 0; c < C; c++) {
            for (int h_out = 0; h_out < H_out; h_out++) {
                for (int w_out = 0; w_out < W_out; w_out++) {
                    /* Calculate input window start position */
                    int h_start = h_out * stride_h - pad_h;
                    int w_start = w_out * stride_w - pad_w;

                    /* Calculate window end position */
                    int h_end = h_start + kernel_h;
                    int w_end = w_start + kernel_w;

                    /* Clamp to input bounds */
                    if (h_start < 0) h_start = 0;
                    if (w_start < 0) w_start = 0;
                    if (h_end > H_in) h_end = H_in;
                    if (w_end > W_in) w_end = W_in;

                    /* Calculate sum and count for averaging */
                    float sum = 0.0f;
                    int count = 0;

                    for (int h = h_start; h < h_end; h++) {
                        for (int w = w_start; w < w_end; w++) {
                            int64_t in_idx = ((n * C + c) * H_in + h) * W_in + w;
                            sum += in_data[in_idx];
                            count++;
                        }
                    }

                    /* Write output (average) */
                    int64_t out_idx = ((n * C + c) * H_out + h_out) * W_out + w_out;
                    out_data[out_idx] = (count > 0) ? (sum / count) : 0.0f;
                }
            }
        }
    }
}

/* ============================================================================
 * Convolution (Placeholder implementation)
 * ============================================================================ */

void nnc_conv(
    Tensor* input, Tensor* weight, Tensor* bias, Tensor* output,
    int kernel_h, int kernel_w,
    int stride_h, int stride_w,
    int pad_h, int pad_w
) {
    /* Standard 2D convolution implementation
     * Input: [N, C_in, H, W]
     * Weight: [C_out, C_in, kH, kW]
     * Bias: [C_out] (optional)
     * Output: [N, C_out, H_out, W_out]
     */

    /* Debug: Check pointers */
    fprintf(stderr, "nnc_conv: Checking pointers...\\n");
    fflush(stderr);

    if (!input || !weight || !output) {
        fprintf(stderr, "nnc_conv: NULL tensor pointer\\n");
        fflush(stderr);
        return;
    }
    if (!input->data || !weight->data || !output->data) {
        fprintf(stderr, "nnc_conv: NULL data pointer\\n");
        fprintf(stderr, "  input->data=%p, weight->data=%p, output->data=%p\\n",
                input->data, weight->data, output->data);
        fflush(stderr);
        return;
    }
    if (!input->shape || !weight->shape || !output->shape) {
        fprintf(stderr, "nnc_conv: NULL shape pointer\\n");
        fflush(stderr);
        return;
    }

    fprintf(stderr, "nnc_conv: All pointers valid\\n");
    fflush(stderr);

    /* Extract dimensions */
    int N = (int)input->shape[0];
    int C_in = (int)input->shape[1];
    int H_in = (int)input->shape[2];
    int W_in = (int)input->shape[3];

    int C_out = (int)weight->shape[0];
    int H_out = (int)output->shape[2];
    int W_out = (int)output->shape[3];

    fprintf(stderr, "nnc_conv: dimensions\\n");
    fprintf(stderr, "  input: [%d, %d, %d, %d]\\n", N, C_in, H_in, W_in);
    fprintf(stderr, "  weight: [%d, %d, %d, %d]\\n", C_out, (int)weight->shape[1], (int)weight->shape[2], (int)weight->shape[3]);
    fprintf(stderr, "  output: [%d, %d, %d, %d]\\n", (int)output->shape[0], (int)output->shape[1], H_out, W_out);
    fprintf(stderr, "  kernel: [%d, %d], stride: [%d, %d], pad: [%d, %d]\\n",
            kernel_h, kernel_w, stride_h, stride_w, pad_h, pad_w);
    fflush(stderr);

    /* Get data pointers */
    float* in_data = (float*)input->data;
    float* weight_data = (float*)weight->data;
    float* bias_data = bias ? (float*)bias->data : NULL;
    float* out_data = (float*)output->data;

    /* Compute output dimensions */
    /* H_out = (H_in + 2*pad_h - kernel_h) / stride_h + 1 */
    /* W_out = (W_in + 2*pad_w - kernel_w) / stride_w + 1 */

    /* Initialize output to zero */
    int64_t output_size = N * C_out * H_out * W_out;
    for (int64_t i = 0; i < output_size; i++) {
        out_data[i] = 0.0f;
    }

    /* Perform convolution */
    for (int n = 0; n < N; n++) {
        for (int c_out = 0; c_out < C_out; c_out++) {
            for (int h_out = 0; h_out < H_out; h_out++) {
                for (int w_out = 0; w_out < W_out; w_out++) {
                    /* Compute convolution window start position */
                    int h_in = h_out * stride_h - pad_h;
                    int w_in = w_out * stride_w - pad_w;

                    float sum = 0.0f;

                    /* Convolve over kernel */
                    for (int c_in = 0; c_in < C_in; c_in++) {
                        for (int kh = 0; kh < kernel_h; kh++) {
                            for (int kw = 0; kw < kernel_w; kw++) {
                                int h = h_in + kh;
                                int w = w_in + kw;

                                /* Check bounds */
                                if (h >= 0 && h < H_in && w >= 0 && w < W_in) {
                                    /* Calculate indices */
                                    int64_t in_idx = n * C_in * H_in * W_in
                                                   + c_in * H_in * W_in
                                                   + h * W_in
                                                   + w;

                                    int64_t weight_idx = c_out * C_in * kernel_h * kernel_w
                                                      + c_in * kernel_h * kernel_w
                                                      + kh * kernel_w
                                                      + kw;

                                    sum += in_data[in_idx] * weight_data[weight_idx];
                                }
                            }
                        }
                    }

                    /* Add bias if present */
                    if (bias_data) {
                        sum += bias_data[c_out];
                    }

                    /* Write output */
                    int64_t out_idx = n * C_out * H_out * W_out
                                    + c_out * H_out * W_out
                                    + h_out * W_out
                                    + w_out;
                    out_data[out_idx] = sum;
                }
            }
        }
    }
}

