void nnc_matmul(Tensor* a, Tensor* b, Tensor* output) {
    /* Matrix multiplication supporting various tensor shapes
     * Handles: 2D matrices, and batched matrix multiplication
     */

    float* a_data = (float*)a->data;
    float* b_data = (float*)b->data;
    float* out_data = (float*)output->data;

    int a_ndim = a->ndim;
    int b_ndim = b->ndim;
    int out_ndim = output->ndim;

    if (a_ndim == 2 && b_ndim == 2) {
        /* Standard 2D matrix multiplication: [M, K] @ [K, N] = [M, N] */
        int M = a->shape[0];
        int K = a->shape[1];
        int N = b->shape[1];

        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                float sum = 0.0f;
                for (int k = 0; k < K; k++) {
                    sum += a_data[i * K + k] * b_data[k * N + j];
                }
                out_data[i * N + j] = sum;
            }
        }
    } else if (a_ndim == 1 && b_ndim == 2) {
        /* Vector @ Matrix: [K] @ [K, N] = [N] */
        int K = a->shape[0];
        int N = b->shape[1];

        for (int j = 0; j < N; j++) {
            float sum = 0.0f;
            for (int k = 0; k < K; k++) {
                sum += a_data[k] * b_data[k * N + j];
            }
            out_data[j] = sum;
        }
    } else if (a_ndim == 2 && b_ndim == 1) {
        /* Matrix @ Vector: [M, K] @ [K] = [M] */
        int M = a->shape[0];
        int K = a->shape[1];

        for (int i = 0; i < M; i++) {
            float sum = 0.0f;
            for (int k = 0; k < K; k++) {
                sum += a_data[i * K + k] * b_data[k];
            }
            out_data[i] = sum;
        }
    } else if (a_ndim >= 2 && b_ndim >= 2) {
        /* Batched matrix multiplication
         * Broadcasting: [B, M, K] @ [B, K, N] or [M, K] @ [B, K, N], etc.
         */

        /* Get batch dimensions */
        int64_t batch_size = 1;
        for (int i = 0; i < out_ndim - 2; i++) {
            batch_size *= output->shape[i];
        }

        /* Get matrix dimensions for the last 2 dimensions */
        int M = output->shape[out_ndim - 2];
        int N = output->shape[out_ndim - 1];
        int K = a->shape[a_ndim - 1];

        /* Calculate strides */
        int64_t a_batch_stride = 1;
        for (int i = 0; i < a_ndim; i++) {
            a_batch_stride *= a->shape[i];
        }
        a_batch_stride /= (a->shape[a_ndim - 2] * a->shape[a_ndim - 1]);

        int64_t b_batch_stride = 1;
        for (int i = 0; i < b_ndim; i++) {
            b_batch_stride *= b->shape[i];
        }
        b_batch_stride /= (b->shape[b_ndim - 2] * b->shape[b_ndim - 1]);

        int64_t out_batch_stride = M * N;

        for (int64_t batch = 0; batch < batch_size; batch++) {
            float* a_batch = a_data + batch * a_batch_stride;
            float* b_batch = b_data + batch * b_batch_stride;
            float* out_batch = out_data + batch * out_batch_stride;

            for (int i = 0; i < M; i++) {
                for (int j = 0; j < N; j++) {
                    float sum = 0.0f;
                    for (int k = 0; k < K; k++) {
                        sum += a_batch[i * K + k] * b_batch[k * N + j];
                    }
                    out_batch[i * N + j] = sum;
                }
            }
        }
    }
}

void nnc_gemm(
    Tensor* a, Tensor* b, Tensor* c, Tensor* output,
    float alpha, float beta, int trans_a, int trans_b
) {
    /* General Matrix Multiply: output = alpha * (A @ B) + beta * C
     *
     * A: input tensor [M, K] or [K, M] if trans_a
     * B: weight tensor [K, N] or [N, K] if trans_b
     * C: bias tensor [N] or [M, N], can be NULL
     * output: [M, N]
     */

    /* Get data pointers */
    float* a_data = (float*)a->data;
    float* b_data = (float*)b->data;
    float* c_data = c ? (float*)c->data : NULL;
    float* out_data = (float*)output->data;

    /* Determine dimensions
     * For 2D tensors:
     * - A: [M, K] (or [K, M] if trans_a)
     * - B: [K, N] (or [N, K] if trans_b)
     * - C: [M, N] (broadcast if 1D)
     * - output: [M, N]
     */
    int M, K, N;

    if (a->ndim == 2 && b->ndim == 2) {
        /* Standard 2D case */
        if (trans_a) {
            K = a->shape[0];
            M = a->shape[1];
        } else {
            M = a->shape[0];
            K = a->shape[1];
        }

        if (trans_b) {
            N = b->shape[0];
            /* K should match: K == b->shape[1] */
        } else {
            N = b->shape[1];
            /* K should match: K == b->shape[0] */
        }
    } else if (a->ndim == 1 && b->ndim == 2) {
        /* Vector x Matrix: [K] x [K, N] -> [N] */
        M = 1;
        K = a->shape[0];
        N = b->shape[1];
        trans_a = 0;  /* Already a vector, no transpose needed */
    } else if (a->ndim == 2 && b->ndim == 1) {
        /* Matrix x Vector: [M, K] x [K] -> [M] */
        M = a->shape[0];
        K = a->shape[1];
        N = 1;
        trans_b = 0;  /* Already a vector, no transpose needed */
    } else {
        /* Fallback: flatten and compute as 2D */
        int64_t a_size = tensor_numel(a);
        int64_t b_size = tensor_numel(b);
        M = 1;
        K = a_size;
        N = b_size;
    }

    /* Compute matrix multiplication
     * output[i][j] = alpha * sum(A[i][k] * B[k][j]) + beta * C[i][j]
     */
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N; j++) {
            float sum = 0.0f;

            /* Compute dot product: A[i,:] @ B[:,j] */
            for (int k = 0; k < K; k++) {
                float a_val, b_val;

                /* Get A[i][k] */
                if (trans_a) {
                    a_val = a_data[k * M + i];  /* [K][M] */
                } else {
                    a_val = a_data[i * K + k];  /* [M][K] */
                }

                /* Get B[k][j] */
                if (trans_b) {
                    b_val = b_data[j * K + k];  /* [N][K] */
                } else {
                    b_val = b_data[k * N + j];  /* [K][N] */
                }

                sum += a_val * b_val;
            }

            /* Apply alpha scaling */
            sum *= alpha;

            /* Add bias (if present) with beta scaling */
            if (c_data != NULL) {
                float c_val;
                if (c->ndim == 1) {
                    /* 1D bias: broadcast along output dimension */
                    c_val = c_data[j];
                } else {
                    /* 2D bias: [M, N] */
                    c_val = c_data[i * N + j];
                }
                sum += beta * c_val;
            }

            out_data[i * N + j] = sum;
        }
    }
}

/* ============================================================================
 * Reduction Operations
 * ============================================================================ */

void nnc_reducemean(Tensor* input, Tensor* output, int axis, int keepdims) {
    /* Mean reduction along specified axis */
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    int ndim = input->ndim;

    /* Handle negative axis */
    if (axis < 0) {
        axis = ndim + axis;
    }

    /* Calculate dimensions */
    int64_t outer_size = 1;
    for (int i = 0; i < axis; i++) {
        outer_size *= input->shape[i];
    }

    int64_t reduce_dim = input->shape[axis];
    int64_t inner_size = 1;
    for (int i = axis + 1; i < ndim; i++) {
        inner_size *= input->shape[i];
    }

    /* Perform reduction */
    for (int64_t outer = 0; outer < outer_size; outer++) {
        for (int64_t inner = 0; inner < inner_size; inner++) {
            float sum = 0.0f;
            for (int64_t r = 0; r < reduce_dim; r++) {
                int64_t idx = outer * reduce_dim * inner_size + r * inner_size + inner;
                sum += in_data[idx];
            }
            float mean = sum / (float)reduce_dim;

            /* Calculate output index */
            int64_t out_idx;
            if (keepdims) {
                out_idx = outer * 1 * inner_size + 0 * inner_size + inner;
            } else {
                out_idx = outer * inner_size + inner;
            }
            out_data[out_idx] = mean;
        }
    }
}

void nnc_reducesum(Tensor* input, Tensor* output, int axis, int keepdims) {
    /* Sum reduction along specified axis */
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    int ndim = input->ndim;

    /* Handle negative axis */
    if (axis < 0) {
        axis = ndim + axis;
    }

    /* Calculate dimensions */
    int64_t outer_size = 1;
    for (int i = 0; i < axis; i++) {
        outer_size *= input->shape[i];
    }

    int64_t reduce_dim = input->shape[axis];
    int64_t inner_size = 1;
    for (int i = axis + 1; i < ndim; i++) {
        inner_size *= input->shape[i];
    }

    /* Perform reduction */
    for (int64_t outer = 0; outer < outer_size; outer++) {
        for (int64_t inner = 0; inner < inner_size; inner++) {
            float sum = 0.0f;
            for (int64_t r = 0; r < reduce_dim; r++) {
                int64_t idx = outer * reduce_dim * inner_size + r * inner_size + inner;
                sum += in_data[idx];
            }

            /* Calculate output index */
            int64_t out_idx;
            if (keepdims) {
                out_idx = outer * 1 * inner_size + 0 * inner_size + inner;
            } else {
                out_idx = outer * inner_size + inner;
            }
            out_data[out_idx] = sum;
        }
    }
}

/* ============================================================================
 * Other Operations
 * ============================================================================ */

void nnc_concat(Tensor** inputs, Tensor* output, int num_inputs, int axis) {
    /* Concatenation along specified axis
     * Combines multiple tensors along a given dimension
     */

    float* out_data = (float*)output->data;

    /* Handle negative axis */
    if (axis < 0) {
        axis = output->ndim + axis;
    }

    /* Calculate dimensions before and after concat axis */
    int64_t outer_size = 1;
    for (int i = 0; i < axis; i++) {
        outer_size *= output->shape[i];
    }

    int64_t inner_size = 1;
    for (int i = axis + 1; i < output->ndim; i++) {
        inner_size *= output->shape[i];
    }

    /* Copy data from each input tensor */
    int64_t output_offset = 0;
    for (int input_idx = 0; input_idx < num_inputs; input_idx++) {
        Tensor* input = inputs[input_idx];
        float* in_data = (float*)input->data;

        int64_t concat_dim = input->shape[axis];
        int64_t copy_size = concat_dim * inner_size;

        for (int64_t outer = 0; outer < outer_size; outer++) {
            int64_t dest_base = outer * output->shape[axis] * inner_size + output_offset;
            int64_t src_base = outer * concat_dim * inner_size;

            for (int64_t i = 0; i < copy_size; i++) {
                out_data[dest_base + i] = in_data[src_base + i];
            }
        }

        output_offset += concat_dim * inner_size;
    }
}

