void nnc_layernorm(
    Tensor* input, Tensor* scale, Tensor* bias, Tensor* output,
    int axis, float epsilon
) {
    /* Layer Normalization implementation
     * Normalizes over the specified axis (typically the last dimension)
     * output = scale * (input - mean) / sqrt(var + epsilon) + bias
     */

    float* in_data = (float*)input->data;
    float* scale_data = scale ? (float*)scale->data : NULL;
    float* bias_data = bias ? (float*)bias->data : NULL;
    float* out_data = (float*)output->data;

    int ndim = input->ndim;

    /* Handle negative axis */
    if (axis < 0) {
        axis = ndim + axis;
    }

    /* Calculate the size of the normalized dimension (feature size) */
    int64_t norm_size = input->shape[axis];

    /* Calculate outer dimensions (number of vectors to normalize) */
    int64_t outer_size = 1;
    for (int i = 0; i < axis; i++) {
        outer_size *= input->shape[i];
    }

    /* Calculate stride between elements in the normalized dimension */
    int64_t inner_size = 1;
    for (int i = axis + 1; i < ndim; i++) {
        inner_size *= input->shape[i];
    }

    /* Process each vector to normalize */
    for (int64_t outer = 0; outer < outer_size; outer++) {
        int64_t base_idx = outer * norm_size * inner_size;

        /* Calculate mean */
        float mean = 0.0f;
        for (int64_t i = 0; i < norm_size; i++) {
            int64_t idx = base_idx + i * inner_size;
            for (int64_t j = 0; j < inner_size; j++) {
                mean += in_data[idx + j];
            }
        }
        mean /= (float)(norm_size * inner_size);

        /* Calculate variance */
        float var = 0.0f;
        for (int64_t i = 0; i < norm_size; i++) {
            int64_t idx = base_idx + i * inner_size;
            for (int64_t j = 0; j < inner_size; j++) {
                float diff = in_data[idx + j] - mean;
                var += diff * diff;
            }
        }
        var /= (float)(norm_size * inner_size);

        /* Calculate standard deviation */
        float std = sqrtf(var + epsilon);

        /* Apply normalization: y = scale * (x - mean) / std + bias */
        for (int64_t i = 0; i < norm_size; i++) {
            int64_t idx = base_idx + i * inner_size;
            float scale_val = scale_data ? scale_data[i] : 1.0f;
            float bias_val = bias_data ? bias_data[i] : 0.0f;

            for (int64_t j = 0; j < inner_size; j++) {
                float normalized = (in_data[idx + j] - mean) / std;
                out_data[idx + j] = scale_val * normalized + bias_val;
            }
        }
    }
}

void nnc_identity(Tensor* input, Tensor* output) {
    /* Identity operation - copy input to output */
    int64_t n = tensor_numel(output);
    int64_t input_n = tensor_numel(input);
    int64_t copy_n = (n < input_n) ? n : input_n;

    /* Use memcpy for safe copy (handles overlap and aliasing correctly) */
    memcpy(output->data, input->data, copy_n * sizeof(float));
}

void nnc_split(Tensor* input, Tensor** outputs, int num_outputs, int axis) {
    /* Split operation - divide tensor along axis
     * For simplicity, this implementation assumes equal splits
     * A full implementation would handle variable split sizes
     */

    float* in_data = (float*)input->data;

    /* Handle negative axis */
    if (axis < 0) {
        axis = input->ndim + axis;
    }

    /* Calculate dimensions before and after split axis */
    int64_t outer_size = 1;
    for (int i = 0; i < axis; i++) {
        outer_size *= input->shape[i];
    }

    int64_t split_dim = input->shape[axis];
    int64_t split_size = split_dim / num_outputs;

    int64_t inner_size = 1;
    for (int i = axis + 1; i < input->ndim; i++) {
        inner_size *= input->shape[i];
    }

    /* Copy data to each output */
    for (int out_idx = 0; out_idx < num_outputs; out_idx++) {
        Tensor* out = outputs[out_idx];
        float* out_data = (float*)out->data;

        for (int outer = 0; outer < outer_size; outer++) {
            /* Calculate source offset for this output */
            int64_t base_src = outer * split_dim * inner_size + out_idx * split_size * inner_size;

            /* Copy this slice */
            int64_t copy_size = split_size * inner_size;
            int64_t dest_offset = outer * split_size * inner_size;

            for (int64_t i = 0; i < copy_size; i++) {
                out_data[dest_offset + i] = in_data[base_src + i];
            }
        }
    }
}

void nnc_clip(Tensor* input, Tensor* output, float min_val, float max_val) {
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        float val = in_data[i];
        out_data[i] = fminf(fmaxf(val, min_val), max_val);
    }
}

void nnc_tile(Tensor* input, Tensor* output, int64_t* repeats, int ndim) {
    /* Tile operation - repeats input tensor along each axis
     * repeats[i] specifies how many times to repeat axis i
     * If repeats is NULL, treat as all 1s (no repetition)
     */

    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    /* If no repeats specified, just copy */
    if (repeats == NULL) {
        int64_t n = tensor_numel(output);
        for (int64_t i = 0; i < n; i++) {
            out_data[i] = in_data[i];
        }
        return;
    }

    /* Calculate strides for input and output tensors */
    int64_t in_strides[8];  /* Max 8 dimensions */
    int64_t out_strides[8];

    /* Compute input strides (row-major) */
    in_strides[input->ndim - 1] = 1;
    for (int i = input->ndim - 2; i >= 0; i--) {
        in_strides[i] = in_strides[i + 1] * input->shape[i + 1];
    }

    /* Compute output strides (row-major) */
    out_strides[output->ndim - 1] = 1;
    for (int i = output->ndim - 2; i >= 0; i--) {
        out_strides[i] = out_strides[i + 1] * output->shape[i + 1];
    }

    /* Broadcast repeats to match input rank if needed */
    int64_t tiled_repeats[8];
    int repeats_offset = ndim > input->ndim ? ndim - input->ndim : 0;

    for (int i = 0; i < input->ndim; i++) {
        int repeats_idx = i + repeats_offset;
        if (repeats_idx < ndim && repeats_idx >= 0) {
            tiled_repeats[i] = repeats[repeats_idx];
        } else {
            tiled_repeats[i] = 1;
        }
    }

    /* Copy data with tiling */
    int64_t out_idx = 0;
    int64_t total_out = tensor_numel(output);

    /* Iterate through output positions */
    for (int64_t out_pos = 0; out_pos < total_out; out_pos++) {
        /* Calculate corresponding input position */
        int64_t in_pos = 0;

        /* Decompose output position to coordinates */
        int64_t temp = out_pos;
        int64_t out_coords[8];
        for (int i = output->ndim - 1; i >= 0; i--) {
            out_coords[i] = temp % output->shape[i];
            temp /= output->shape[i];
        }

        /* Map output coordinates to input coordinates */
        for (int i = 0; i < input->ndim; i++) {
            int64_t coord = out_coords[i] % input->shape[i];
            in_pos += coord * in_strides[i];
        }

        out_data[out_pos] = in_data[in_pos];
    }
}

/* ============================================================================
 * Comparison Operations
 * ============================================================================ */

void nnc_equal(Tensor* a, Tensor* b, Tensor* out) {
    /* Element-wise equality comparison
     * Returns 1.0f where a == b, 0.0f otherwise
     */
    int64_t n = tensor_numel(out);
    int64_t a_n = tensor_numel(a);
    int64_t b_n = tensor_numel(b);

    float* a_data = (float*)a->data;
    float* b_data = (float*)b->data;
    float* out_data = (float*)out->data;

    /* Handle broadcasting - use minimum size */
    int64_t compare_n = n;
    if (a_n < compare_n) compare_n = a_n;
    if (b_n < compare_n) compare_n = b_n;

    /* Compare elements */
    for (int64_t i = 0; i < compare_n; i++) {
        out_data[i] = (a_data[i] == b_data[i]) ? 1.0f : 0.0f;
    }

    /* Handle broadcast: if one input is smaller, broadcast its value */
    if (a_n == 1 && b_n == n) {
        for (int64_t i = compare_n; i < n; i++) {
            out_data[i] = (a_data[0] == b_data[i]) ? 1.0f : 0.0f;
        }
    } else if (a_n == n && b_n == 1) {
        for (int64_t i = compare_n; i < n; i++) {
            out_data[i] = (a_data[i] == b_data[0]) ? 1.0f : 0.0f;
        }
    } else if (a_n < n && b_n == n) {
        /* Broadcast a (e.g., [6] to [2, 6]) */
        for (int64_t i = compare_n; i < n; i++) {
            out_data[i] = (a_data[i % a_n] == b_data[i]) ? 1.0f : 0.0f;
        }
    } else if (a_n == n && b_n < n) {
        /* Broadcast b (e.g., [6] to [2, 6]) */
        for (int64_t i = compare_n; i < n; i++) {
            out_data[i] = (a_data[i] == b_data[i % b_n]) ? 1.0f : 0.0f;
        }
    }
}

void nnc_and(Tensor* a, Tensor* b, Tensor* out) {
    /* Logical AND operation
     * Inputs are float (non-zero = true), output is float (1.0 = true, 0.0 = false)
     */
    int64_t n = tensor_numel(out);
    int64_t a_n = tensor_numel(a);
    int64_t b_n = tensor_numel(b);

    const float* a_data = (float*)a->data;
    const float* b_data = (float*)b->data;
    float* out_data = (float*)out->data;

    /* Handle broadcasting */
    int64_t and_n = n;
    if (a_n < and_n) and_n = a_n;
    if (b_n < and_n) and_n = b_n;

    /* Compute AND for overlapping region */
    for (int64_t i = 0; i < and_n; i++) {
        out_data[i] = (a_data[i] != 0.0f && b_data[i] != 0.0f) ? 1.0f : 0.0f;
    }

    /* Handle broadcast: if one input is smaller, broadcast its value */
    if (a_n == 1 && b_n == n) {
        for (int64_t i = and_n; i < n; i++) {
            out_data[i] = (a_data[0] != 0.0f && b_data[i] != 0.0f) ? 1.0f : 0.0f;
        }
    } else if (a_n == n && b_n == 1) {
        for (int64_t i = and_n; i < n; i++) {
            out_data[i] = (a_data[i] != 0.0f && b_data[0] != 0.0f) ? 1.0f : 0.0f;
        }
    } else if (a_n < n && b_n == n) {
        /* Broadcast a (e.g., [2] to [2, 2]) */
        for (int64_t i = and_n; i < n; i++) {
            out_data[i] = (a_data[i % a_n] != 0.0f && b_data[i] != 0.0f) ? 1.0f : 0.0f;
        }
    } else if (a_n == n && b_n < n) {
        /* Broadcast b (e.g., [2] to [2, 2]) */
        for (int64_t i = and_n; i < n; i++) {
            out_data[i] = (a_data[i] != 0.0f && b_data[i % b_n] != 0.0f) ? 1.0f : 0.0f;
        }
    }
}

/* ============================================================================
 * Math Operations (Unary Element-wise)
 * ============================================================================ */

void nnc_sqrt(Tensor* input, Tensor* output) {
    /* Element-wise square root operation
     * Computes sqrt(x) for each element
     */
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        float x = in_data[i];
        /* Handle negative inputs - return NaN for sqrt of negative numbers */
        out_data[i] = (x >= 0.0f) ? sqrtf(x) : NAN;
    }
}

void nnc_pow(Tensor* input, Tensor* output) {
    /* Element-wise power operation (x^2)
     * Used for LayerNorm variance computation
     * Computes x^2 for each element
     */
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = in_data[i] * in_data[i];
    }
}

void nnc_exp(Tensor* input, Tensor* output) {
    /* Element-wise exponential operation
     * Computes exp(x) for each element
     */
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = expf(in_data[i]);
    }
}

void nnc_log(Tensor* input, Tensor* output) {
    /* Element-wise natural logarithm operation
     * Computes log(x) for each element
     */
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        float x = in_data[i];
        /* Handle non-positive inputs - return NaN */
        out_data[i] = (x > 0.0f) ? logf(x) : NAN;
    }
}

void nnc_abs(Tensor* input, Tensor* output) {
    /* Element-wise absolute value operation
     * Computes |x| for each element
     */
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = fabsf(in_data[i]);
    }
}

void nnc_neg(Tensor* input, Tensor* output) {
    /* Element-wise negation operation
     * Computes -x for each element
     */
    int64_t n = tensor_numel(output);
    float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = -in_data[i];
    }
}

void nnc_cast(Tensor* input, Tensor* output, int to_dtype) {
    /* Cast operation - convert tensor data type
     * to_dtype: NNC_DTYPE_* constant
     */
    int64_t n = tensor_numel(input);

    switch (to_dtype) {
        case NNC_DTYPE_FLOAT32: {
            /* Check if input is BOOL type by checking dtype field */
            int is_bool_input = (input->dtype == NNC_DTYPE_BOOL);
            if (is_bool_input) {
                /* BOOL to FLOAT32 - convert properly */
                const uint8_t* in_data = (uint8_t*)input->data;
                float* out_data = (float*)output->data;
                for (int64_t i = 0; i < n; i++) {
                    out_data[i] = (float)in_data[i];
                }
            } else {
                /* Float to float - copy */
                memcpy(output->data, input->data, n * sizeof(float));
            }
            break;
        }
        case NNC_DTYPE_FLOAT16:
            /* Float to float - copy (with size conversion) */
            memcpy(output->data, input->data, n * sizeof(float));
            break;
        case NNC_DTYPE_INT32: {
            /* Float to int32 */
            const float* in_data = (float*)input->data;
            int32_t* out_data = (int32_t*)output->data;
            for (int64_t i = 0; i < n; i++) {
                out_data[i] = (int32_t)in_data[i];
            }
            break;
        }
        case NNC_DTYPE_INT64: {
            /* Float to int64 */
            const float* in_data = (float*)input->data;
            int64_t* out_data = (int64_t*)output->data;
            for (int64_t i = 0; i < n; i++) {
                out_data[i] = (int64_t)in_data[i];
            }
            break;
        }
        case NNC_DTYPE_BOOL: {
            /* Float to bool (non-zero is true) */
            const float* in_data = (float*)input->data;
            uint8_t* out_data = (uint8_t*)output->data;
            for (int64_t i = 0; i < n; i++) {
                out_data[i] = in_data[i] != 0.0f ? 1 : 0;
            }
            break;
        }
        default:
            /* Unsupported cast, copy as fallback */
            memcpy(output->data, input->data, n * sizeof(float));
            break;
    }
}

void nnc_shape(Tensor* input, Tensor* output, int64_t* shape_data, int ndim) {
    /* Shape operation - extracts the shape of input tensor
     * If shape_data is provided, use it (compile-time known shape)
     * Otherwise, extract from input tensor
     */
    int64_t* out_data = (int64_t*)output->data;

    if (shape_data != NULL) {
        /* Compile-time known shape - just copy */
        for (int i = 0; i < ndim; i++) {
            out_data[i] = shape_data[i];
        }
    } else {
        /* Runtime shape extraction */
        for (int i = 0; i < ndim; i++) {
            out_data[i] = input->shape[i];
        }
    }
}

void nnc_constantofshape(Tensor* output, float value, int ndim) {
    /* ConstantOfShape operation - create tensor filled with value
     * The shape is determined from the tensor's shape field
     */
    int64_t n = tensor_numel(output);
    float* out_data = (float*)output->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = value;
    }
}

void nnc_expand(Tensor* input, Tensor* output, int64_t* shape, int ndim) {
    /* Expand operation - broadcast tensor to larger shape
     * For simplicity, we just copy the data with broadcasting logic
     * In a full implementation, this would handle proper broadcasting
     */
    int64_t in_n = tensor_numel(input);
    int64_t out_n = tensor_numel(output);

    const float* in_data = (float*)input->data;
    float* out_data = (float*)output->data;

    if (in_n == out_n) {
        /* Same size, just copy */
        memcpy(out_data, in_data, in_n * sizeof(float));
    } else {
        /* Simple broadcast - repeat input data */
        for (int64_t i = 0; i < out_n; i++) {
            out_data[i] = in_data[i % in_n];
        }
    }
}

void nnc_greater(Tensor* a, Tensor* b, Tensor* out) {
    /* Greater comparison: out = (a > b)
     * Output is uint8_t (BOOL type)
     * Supports broadcasting when one input is scalar (1 element)
     */
    int64_t n = tensor_numel(out);
    int64_t a_n = tensor_numel(a);
    int64_t b_n = tensor_numel(b);
    const float* a_data = (float*)a->data;
    const float* b_data = (float*)b->data;
    uint8_t* out_data = (uint8_t*)out->data;

    for (int64_t i = 0; i < n; i++) {
        float a_val = a_data[i % a_n];
        float b_val = b_data[i % b_n];
        out_data[i] = a_val > b_val ? 1 : 0;
    }
}

void nnc_or(Tensor* a, Tensor* b, Tensor* out) {
    /* Logical OR operation
     * Inputs and output are uint8_t (BOOL type)
     */
    int64_t n = tensor_numel(out);
    const uint8_t* a_data = (uint8_t*)a->data;
    const uint8_t* b_data = (uint8_t*)b->data;
    uint8_t* out_data = (uint8_t*)out->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = a_data[i] || b_data[i] ? 1 : 0;
    }
}

void nnc_not(Tensor* input, Tensor* output) {
    /* Logical NOT operation
     * Input and output are uint8_t (BOOL type)
     */
    int64_t n = tensor_numel(output);
    const uint8_t* in_data = (uint8_t*)input->data;
    uint8_t* out_data = (uint8_t*)output->data;

    for (int64_t i = 0; i < n; i++) {
        out_data[i] = !in_data[i] ? 1 : 0;
    }
}
